### `calculateDiscount.ts`

```typescript
export interface Customer {
  accountCreatedAt: Date;          // used to determine account age
  lastPurchaseAt: Date | null;     // null = no purchase history
}

/**
 * Calculates the discount rate for a customer based on account age
 * and recent purchase activity.
 *
 * AC1: New customer (account age < 30 days)                          → 5%
 * AC2: Returning customer, no purchase in last 90 days (win-back)    → 3%
 * AC3: Returning customer with purchase in last 90 days              → 0%
 */
export function calculateDiscount(customer: Customer): number {
  const now = new Date();

  const accountAgeMs = now.getTime() - customer.accountCreatedAt.getTime();
  const accountAgeDays = accountAgeMs / (1000 * 60 * 60 * 24);

  // AC1: New customer
  if (accountAgeDays < 30) {
    return 0.05;
  }

  // AC2 / AC3: Returning customer — check for recent purchase activity
  const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
  const hasRecentPurchase =
    customer.lastPurchaseAt !== null &&
    customer.lastPurchaseAt >= ninetyDaysAgo;

  if (!hasRecentPurchase) {
    return 0.03; // AC2: win-back rate
  }

  return 0; // AC3: active customer, no discount
}
```

