### `calculateDiscount.test.ts`

```typescript
import { calculateDiscount, Customer } from "./calculateDiscount";

describe("calculateDiscount", () => {
  const now = new Date();
  const daysAgo = (days: number): Date =>
    new Date(now.getTime() - days * 24 * 60 * 60 * 1000);

  // ── AC1: New customer (account age < 30 days) ────────────────────────────

  it("AC1: returns 5% for a brand-new customer (1 day old, no purchases)", () => {
    const customer: Customer = { accountCreatedAt: daysAgo(1), lastPurchaseAt: null };
    expect(calculateDiscount(customer)).toBe(0.05);
  });

  it("AC1: returns 5% for a customer created 29 days ago (boundary)", () => {
    const customer: Customer = { accountCreatedAt: daysAgo(29), lastPurchaseAt: null };
    expect(calculateDiscount(customer)).toBe(0.05);
  });

  it("AC1: returns 5% for a new customer who has already made a purchase", () => {
    // New customer discount takes precedence — account age wins
    const customer: Customer = { accountCreatedAt: daysAgo(15), lastPurchaseAt: daysAgo(5) };
    expect(calculateDiscount(customer)).toBe(0.05);
  });

  // ── AC2: Returning customer, no purchase in last 90 days (win-back) ──────

  it("AC2: returns 3% for a returning customer with no purchase history", () => {
    const customer: Customer = { accountCreatedAt: daysAgo(60), lastPurchaseAt: null };
    expect(calculateDiscount(customer)).toBe(0.03);
  });

  it("AC2: returns 3% for a returning customer whose last purchase was 91 days ago", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(200),
      lastPurchaseAt: daysAgo(91),
    };
    expect(calculateDiscount(customer)).toBe(0.03);
  });

  it("AC2: returns 3% for a returning customer whose last purchase was exactly 90 days + 1ms ago", () => {
    const justOver90Days = new Date(now.getTime() - (90 * 24 * 60 * 60 * 1000 + 1));
    const customer: Customer = { accountCreatedAt: daysAgo(180), lastPurchaseAt: justOver90Days };
    expect(calculateDiscount(customer)).toBe(0.03);
  });

  // ── AC3: Returning customer with purchase in last 90 days → no discount ──

  it("AC3: returns 0% for a returning customer who purchased 30 days ago", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(90),
      lastPurchaseAt: daysAgo(30),
    };
    expect(calculateDiscount(customer)).toBe(0);
  });

  it("AC3: returns 0% for a returning customer who purchased exactly 90 days ago (boundary)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(180),
      lastPurchaseAt: daysAgo(90),
    };
    expect(calculateDiscount(customer)).toBe(0);
  });

  it("AC3: returns 0% for a returning customer who purchased yesterday", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(365),
      lastPurchaseAt: daysAgo(1),
    };
    expect(calculateDiscount(customer)).toBe(0);
  });
});
```

